   169→  // ==========================================================================
   170→  // POST /api/room/:code/validate-token - Validate JWT token and return room info
   171→  // ==========================================================================
   172→  // NOTE: No authentication required - the JWT token IS the authentication
   173→
   174→  fastify.post('/api/room/:code/validate-token', {
   175→    schema: {
   176→      params: {
   177→        type: 'object',
   178→        properties: {
   179→          code: { type: 'string' }
   180→        },
   181→        required: ['code']
   182→      },
   183→      body: {
   184→        type: 'object',
   185→        properties: {
   186→          token: { type: 'string' }
   187→        },
   188→        required: ['token']
   189→      }
   190→    }
   191→  },
   192→  handler: async (request, reply) => {
   193→    const { code } = request.params as { code: string };
   194→    const { token } = request.body as { token: string };
   195→
   196→    try {
   197→      // Verify JWT token using Fastify's JWT plugin
   198→      const decoded = fastify.jwt.verify(token) as any;
   199→
   200→      // Check if token matches this room (case-insensitive)
   201→      if (decoded.roomCode?.toUpperCase() !== code.toUpperCase()) {
   202→        return reply.code(403).send({
   203→          success: false,
   204→          error: 'Token does not match this room'
   205→        });
   206→      }
   207→
   208→      // Check if token is expired (jwt.verify should handle this, but double-check)
   209→      if (decoded.exp && decoded.exp < Date.now() / 1000) {
   210→        return reply.code(403).send({
   211→          success: false,
   212→          error: 'Token has expired'
   213→        });
   214→      }
   215→
   216→      // Get room info with current enrollment count
   217→      const roomResult = await fastify.pg.query(
   218→        `SELECT r.id, r.room_code, r.capacity, r.status,
   219→                COUNT(e.id) as current_enrolled
   220→         FROM proctoring_rooms r
   221→         LEFT JOIN room_enrollments e ON e.room_id = r.id
   222→         WHERE r.room_code = $1
   223→         GROUP BY r.id`,
   224→        [code.toUpperCase()]
   225→      );
   226→
   227→      if (roomResult.rows.length === 0) {
   228→        return reply.code(404).send({
   229→          success: false,
   230→          error: 'Room not found'
   231→        });
   232→      }
   233→
   234→      const room = roomResult.rows[0];
   235→
   236→      // Check if room is active
   237→      if (room.status !== 'activated') {
   238→        return reply.code(400).send({
   239→          success: false,
   240→          error: 'Room is not active'
   241→        });
   242→      }
   243→
   244→      // Check capacity (prevent over-enrollment at validation stage)
   245→      const currentEnrolled = parseInt(room.current_enrolled) || 0;
   246→      if (currentEnrolled >= room.capacity) {
   247→        return reply.code(429).send({
   248→          success: false,
   249→          error: `Room is full (${currentEnrolled}/${room.capacity} students enrolled)`
   250→        });
   251→      }
   252→
   253→      return reply.send({
   254→        success: true,
   255→        data: {
   256→          roomId: room.id,
   257→          roomCode: room.room_code,
   258→          capacity: room.capacity,
   259→          currentEnrolled: currentEnrolled,
   260→          userId: decoded.userId
   261→        }
   262→      });
   263→
   264→    } catch (error) {
   265→      const errorObj = error as any;
   266→
   267→      if (errorObj.name === 'JsonWebTokenError' || errorObj.code === 'FAST_JWT_NO_ACTIVE') {
   268→        return reply.code(403).send({
   269→          success: false,
   270→          error: 'Invalid token'
   271→        });
   272→      }
   273→
   274→      if (errorObj.name === 'TokenExpiredError') {
   275→        return reply.code(403).send({
   276→          success: false,
   277→          error: 'Token has expired'
   278→        });
   279→      }
