   349→          }
   350→        };
   351→      } catch (error) {
   352→        const errorObj = error as any;
   353→
   354→        // Handle specific error types with clear messages
   355→        if (errorObj.name === 'RoomNotFoundError') {
   356→          return reply.code(404).send({
