        [capacity, roomId]
      );

      return reply.send({
        success: true,
        data: updateResult.rows[0]
      });

    } catch (error) {
      const errorObj = error as any;

      // Database-specific error handling
      if (errorObj.code === 'ECONNREFUSED' ||
